class Solution:
    def moveZeroes(self, nums: list[int]) -> None:
        slow = 0                           # slow 指向「下一个非零数该放的位置」
        for fast in range(len(nums)):      # fast 扫描整个数组
            if nums[fast]:                 # 当前是非零数(0 为假)
                nums[slow], nums[fast] = nums[fast], nums[slow]  # 交换到前面
                slow += 1                  # slow 前进一格
